/**
 * Navbar.jsx
 * ─────────────────────────────────────────────────────────────
 * Barra de navegación superior.
 * Incluye: logo, saludo al usuario, toggle de tema y logout.
 */

import { useAuth }      from '../../context/AuthContext'
import ThemeToggle      from '../common/ThemeToggle'
import Button           from '../common/Button'
import styles           from './Navbar.module.css'

export default function Navbar() {
  const { user, logout } = useAuth()

  // Hora del día para saludo personalizado
  const hour = new Date().getHours()
  const greeting =
    hour < 12 ? 'Buenos días' :
    hour < 18 ? 'Buenas tardes' : 'Buenas noches'

  return (
    <header className={styles.navbar}>
      {/* Logo */}
      <div className={styles.brand}>
        <span className={styles.brandIcon}>◈</span>
        <span className={styles.brandName}>Finanzas</span>
      </div>

      {/* Acciones del lado derecho */}
      <div className={styles.actions}>
        {user && (
          <span className={styles.greeting}>
            {greeting}, <strong>{user.name.split(' ')[0]}</strong>
          </span>
        )}

        <ThemeToggle />

        {user && (
          <Button variant="ghost" size="sm" onClick={logout}>
            Salir
          </Button>
        )}
      </div>
    </header>
  )
}
